1	------------------------------------------------------------------------------
2	--  Copyright (c) 2018 by Paul Scherrer Institute, Switzerland
3	--  All rights reserved.
4	--  Authors: Oliver Bruendler, Radoslaw Rybaniec
5	------------------------------------------------------------------------------
6	
7	------------------------------------------------------------------------------
8	-- Description
9	------------------------------------------------------------------------------
10	-- This component calculateas an FIR filter with the following limitations:
11	-- - Filter is calculated serially (one tap after the other)
12	-- - The number of channels is configurable
13	-- - All channels are processed in parallel and their data must be synchronized
14	-- - Coefficients are configurable but the same for each channel
15	------------------------------------------------------------------------------
16	--
17	-- Required Memory depth per channel = max_taps_g + max_ratio_g
18	
19	library ieee;
20	use ieee.std_logic_1164.all;
21	use ieee.numeric_std.all;
22	
23	use work.psi_fix_pkg.all;
24	use work.psi_common_math_pkg.all;
25	use work.psi_common_array_pkg.all;
26	
27	entity psi_fix_fir_dec_ser_nch_chtdm_conf is
28	  generic(
29	    in_fmt_g        : psi_fix_fmt_t := (1, 0, 17);      -- internal format
30	    out_fmt_g       : psi_fix_fmt_t := (1, 0, 17);      -- output format
31	    coef_fmt_g      : psi_fix_fmt_t := (1, 0, 17);      -- coefficient format
32	    channels_g      : natural     := 2;                 -- channels
33	    max_ratio_g     : natural     := 8;                 -- max decimation ratio
34	    max_taps_g      : natural     := 1024;              -- max number of taps
35	    rnd_g           : psi_fix_rnd_t := psi_fix_round;   -- rounding truncation
36	    sat_g           : psi_fix_sat_t := psi_fix_sat;     -- saturate or wrap
37	    use_fix_coefs_g : boolean     := false;             -- use fix coefficients or update them
38	    coefs_g         : t_areal     := (0.0, 0.0);        -- see doc
39	    ram_behavior_g  : string      := "RBW";             -- RBW = Read before write, WBR = Write before read
40	    rst_pol_g      : std_logic   := '1'                 -- reset polarity active high ='1'
41	  );
42	  port(
43	    clk_i            : in  std_logic;                                             -- system clock
44	    rst_i            : in  std_logic;                                             -- system reset
45	    dat_i            : in  std_logic_vector(psi_fix_size(in_fmt_g) - 1 downto 0); -- data input
46	    vld_i            : in  std_logic;                                             -- valid input Frequency sampling
47	    dat_o            : out std_logic_vector(psi_fix_size(out_fmt_g) - 1 downto 0);-- data output
48	    vld_o            : out std_logic;                                             -- valid output new frequency sampling
49	    -- Parallel Configuration Interface
50	    cfg_ratio_i      : in  std_logic_vector(log2ceil(max_ratio_g) - 1 downto 0)  := std_logic_vector(to_unsigned(max_ratio_g - 1, log2ceil(max_ratio_g))); -- Ratio - 1 (0 => Ratio 1, 4 => Ratio 5)
51	    cfg_taps_i       : in  std_logic_vector(log2ceil(max_taps_g) - 1 downto 0)   := std_logic_vector(to_unsigned(max_taps_g - 1, log2ceil(max_taps_g)));   -- Number of taps - 1
52	    -- Coefficient interface
53	    coef_if_clk_i    : in  std_logic                                            := '0';                 -- clock for coef intereface
54	    coef_if_wr_i     : in  std_logic                                            := '0';                 -- write enable
55	    coef_if_addr_i   : in  std_logic_vector(log2ceil(max_taps_g) - 1 downto 0)   := (others => '0');    -- address of coef access
56	    coef_if_wr_dat_i : in  std_logic_vector(psi_fix_size(coef_fmt_g) - 1 downto 0) := (others => '0');  -- coef to write
57	    coef_if_rd_dat_o : out std_logic_vector(psi_fix_size(coef_fmt_g) - 1 downto 0);                     -- coef read
58	    -- Status Output
59	    busy_o           : out std_logic                                                                    -- calculation on going active high
60	  );
61	end entity;
62	
63	architecture rtl of psi_fix_fir_dec_ser_nch_chtdm_conf is
64	
65	  -- Data Memory needs twice the depth since a almost a full set of data can arrive until the last channel is fully processed
66	  constant DataMemDepthRequired_c : natural := max_taps_g + max_ratio_g; -- max_ratio_g is the maximum samples to arrive before a calculation starts
67	  constant DataMemAddBits_c       : natural := log2ceil(DataMemDepthRequired_c);
68	  constant DataMemDepthApplied_c  : natural := 2**DataMemAddBits_c;
69	  constant CoefMemDepthApplied_c  : natural := 2**log2ceil(max_taps_g);
70	
71	  -- Constants
72	  constant MultFmt_c : psi_fix_fmt_t := (max(in_fmt_g.S, coef_fmt_g.S), in_fmt_g.I + coef_fmt_g.I, in_fmt_g.F + coef_fmt_g.F);
73	  constant AccuFmt_c : psi_fix_fmt_t := (1, out_fmt_g.I + 1, in_fmt_g.F + coef_fmt_g.F);
74	  constant RndFmt_c  : psi_fix_fmt_t := (1, out_fmt_g.I + 1, out_fmt_g.F);
75	
76	  -- types
77	  subtype InData_t is std_logic_vector(psi_fix_size(in_fmt_g) - 1 downto 0);
78	  type InData_a is array (natural range <>) of InData_t;
79	  subtype Mult_t is std_logic_vector(psi_fix_size(MultFmt_c) - 1 downto 0);
80	  subtype Accu_t is std_logic_vector(psi_fix_size(AccuFmt_c) - 1 downto 0);
81	  subtype Rnd_t is std_logic_vector(psi_fix_size(RndFmt_c) - 1 downto 0);
82	  subtype Out_t is std_logic_vector(psi_fix_size(out_fmt_g) - 1 downto 0);
83	  type ChNr_a is array (natural range <>) of std_logic_vector(log2ceil(channels_g) - 1 downto 0);
84	
85	  -- Two process method
86	  type two_process_r is record
87	    FirstAfterRst  : std_logic;
88	    Vld            : std_logic_vector(0 to 1);
89	    InSig          : InData_a(0 to 1);
90	    ChannelNr      : ChNr_a(0 to 3);
91	    TapWrAddr_1    : std_logic_vector(DataMemAddBits_c - 1 downto 0);
92	    Tap0Addr_1     : std_logic_vector(DataMemAddBits_c - 1 downto 0);
93	    DecCnt_1       : std_logic_vector(log2ceil(max_ratio_g) - 1 downto 0);
94	    TapCnt_1       : std_logic_vector(log2ceil(max_taps_g) - 1 downto 0);
95	    CalcChnl_1     : std_logic_vector(log2ceil(channels_g) - 1 downto 0);
96	    CalcChnl_2     : std_logic_vector(log2ceil(channels_g) - 1 downto 0);
97	    TapRdAddr_2    : std_logic_vector(DataMemAddBits_c - 1 downto 0);
98	    CoefRdAddr_2   : std_logic_vector(log2ceil(max_taps_g) - 1 downto 0);
99	    CalcOn         : std_logic_vector(1 to 7);
100	    Last           : std_logic_vector(1 to 7);
101	    First          : std_logic_vector(1 to 6);
102	    MultInTap_4    : InData_t;
103	    MultInCoef_4   : std_logic_vector(psi_fix_size(coef_fmt_g) - 1 downto 0);
104	    MultInTap_5    : InData_t;
105	    MultInCoef_5   : std_logic_vector(psi_fix_size(coef_fmt_g) - 1 downto 0);
106	    MultOut_6      : Mult_t;
107	    Accu_7         : Accu_t;
108	    Rnd_8          : Rnd_t;
109	    RndVld_8       : std_logic;
110	    Output_9       : Out_t;
111	    OutVld_9       : std_logic;
112	    FirstTapLoop_3 : std_logic;
113	    TapRdAddr_3    : std_logic_vector(DataMemAddBits_c - 1 downto 0);
114	    ReplaceZero_4  : std_logic;
115	    -- Status
116	    CalcOngoing    : std_logic;
117	  end record;
118	  signal r, r_next : two_process_r;
119	
120	  -- Component Interface Signals
121	  signal DataRamWrAddr_1 : std_logic_vector(DataMemAddBits_c + log2ceil(channels_g) - 1 downto 0);
122	  signal DataRamRdAddr_2 : std_logic_vector(DataMemAddBits_c + log2ceil(channels_g) - 1 downto 0);
123	  signal DataRamDout_3   : std_logic_vector(psi_fix_size(in_fmt_g) - 1 downto 0);
124	  signal CoefRamDout_3   : std_logic_vector(psi_fix_size(coef_fmt_g) - 1 downto 0);
125	
126	  -- coef ROM
127	  type CoefRom_t is array (0 to 2**log2ceil(max_taps_g) - 1) of std_logic_vector(psi_fix_size(coef_fmt_g) - 1 downto 0); -- full power of two to ensure index is always valid
128	  signal CoefRom : CoefRom_t := (others => (others => '0'));
129	
130	begin
131	
132	  assert channels_g >= 2 report "###ERROR###: psi_fix_fir_dec_ser_nch_chtdm_conf only works for channels_g >= 2, use psi_fix_fir_dec_ser_nch_chtpar_conf for single channel implementation" severity error;
133	
134	  --------------------------------------------
135	  -- Combinatorial Process
136	  --------------------------------------------
137	  p_comb : process(r, vld_i, dat_i, cfg_ratio_i, cfg_taps_i, DataRamDout_3, CoefRamDout_3)
138	    variable v        : two_process_r;
139	    variable AccuIn_v : std_logic_vector(psi_fix_size(AccuFmt_c) - 1 downto 0);
140	  begin
141	    -- *** Hold variables stable ***
142	    v := r;
143	
144	    -- *** Pipe Handling ***
145	    v.Vld(v.Vld'low + 1 to v.Vld'high)                   := r.Vld(r.Vld'low to r.Vld'high - 1);
146	    v.InSig(v.InSig'low + 1 to v.InSig'high)             := r.InSig(r.InSig'low to r.InSig'high - 1);
147	    v.CalcOn(v.CalcOn'low + 1 to v.CalcOn'high)          := r.CalcOn(r.CalcOn'low to r.CalcOn'high - 1);
148	    v.Last(v.Last'low + 1 to v.Last'high)                := r.Last(r.Last'low to r.Last'high - 1);
149	    v.First(v.First'low + 1 to v.First'high)             := r.First(r.First'low to r.First'high - 1);
150	    v.ChannelNr(v.ChannelNr'low + 1 to v.ChannelNr'high) := r.ChannelNr(r.ChannelNr'low to r.ChannelNr'high - 1);
151	
152	    -- *** Stage 0 ***
153	    -- Input Registers
154	    v.Vld(0)   := vld_i;
155	    v.InSig(0) := dat_i;
156	
157	    -- Calculate channel number
158	    if vld_i = '1' then
159	      if unsigned(r.ChannelNr(0)) = channels_g - 1 or r.FirstAfterRst = '1' then
160	        v.ChannelNr(0)  := (others => '0');
161	        v.FirstAfterRst := '0';
162	      else
163	        v.ChannelNr(0) := std_logic_vector(unsigned(r.ChannelNr(0)) + 1);
164	      end if;
165	    end if;
166	
167	    -- *** Stage 1 ***
168	    -- Increment tap address after data was written for last channel
169	    if (r.Vld(1) = '1') and (unsigned(r.ChannelNr(1)) = channels_g - 1) then
170	      v.TapWrAddr_1 := std_logic_vector(unsigned(r.TapWrAddr_1) + 1);
171	    end if;
172	
173	    -- Decimation & Calculation Control
174	    -- Initial value
175	    v.First(1) := '0';
176	    v.Last(1)  := '0';
177	
178	    -- normal update
179	    v.TapCnt_1 := std_logic_vector(unsigned(r.TapCnt_1) - 1);
180	    -- last tap of a channel
181	    if unsigned(r.TapCnt_1) = 1 or unsigned(cfg_taps_i) = 0 then
182	      v.Last(1) := '1';
183	    end if;
184	    -- goto next channel or finish calculation
185	    if unsigned(r.TapCnt_1) = 0 then
186	      -- last channel
187	      if unsigned(r.CalcChnl_1) = channels_g - 1 then
188	        v.CalcOn(1) := '0';
189	      -- goto next channel
190	      else
191	        v.First(1)   := '1';
192	        v.CalcChnl_1 := std_logic_vector(unsigned(r.CalcChnl_1) + 1);
193	        v.TapCnt_1   := cfg_taps_i;
194	      end if;
195	    end if;
196	
197	    -- start of calculation and decimation
198	    if r.Vld(0) = '1' then
199	      -- Start calculation (data from all channels available)
200	      if unsigned(r.ChannelNr(0)) = channels_g - 1 then
201	        if (unsigned(r.DecCnt_1) = 0) or (max_ratio_g = 0) then
202	          v.Tap0Addr_1 := r.TapWrAddr_1;
203	          v.TapCnt_1   := cfg_taps_i;
204	          v.CalcOn(1)  := '1';
205	          v.First(1)   := '1';
206	          v.CalcChnl_1 := (others => '0');
207	          v.DecCnt_1   := cfg_ratio_i;
208	        else
209	          v.DecCnt_1 := std_logic_vector(unsigned(r.DecCnt_1) - 1);
210	        end if;
211	      end if;
212	    end if;
213	
214	    -- *** Stage 2 ***
215	    -- pipelining
216	    v.CalcChnl_2 := r.CalcChnl_1;
217	
218	    -- Tap read address
219	    v.TapRdAddr_2  := std_logic_vector(unsigned(r.Tap0Addr_1) - unsigned(r.TapCnt_1));
220	    v.CoefRdAddr_2 := r.TapCnt_1;
221	
222	    -- *** Stage 3 ***
223	    -- Pipelining
224	    v.TapRdAddr_3 := r.TapRdAddr_2;
225	
226	    -- *** Stage 4 ***
227	    -- Multiplier input registering
228	    -- Replace taps that are not yet written with zeros for bittrueness
229	    if r.ReplaceZero_4 = '0' or unsigned(r.TapRdAddr_3) <= unsigned(cfg_ratio_i) then
230	      v.MultInTap_4 := DataRamDout_3;
231	    else
232	      v.MultInTap_4 := (others => '0');
233	    end if;
234	    -- Detect when the Zero-replacement can be stopped since the taps are already filled with correct data
235	    if r.FirstTapLoop_3 = '0' then
236	      v.ReplaceZero_4 := '0';
237	    elsif r.CalcOn(3) = '1' then
238	      if r.First(3) = '1' and unsigned(r.TapRdAddr_3) <= unsigned(cfg_ratio_i) then
239	        v.ReplaceZero_4 := '0';
240	        if unsigned(r.ChannelNr(3)) = channels_g - 1 then
241	          v.FirstTapLoop_3 := '0';
242	        end if;
243	      elsif r.Last(3) = '1' then
244	        v.ReplaceZero_4 := '1';
245	      elsif unsigned(r.TapRdAddr_3) = 0 then
246	        v.ReplaceZero_4 := '0';
247	      end if;
248	    end if;
249	    v.MultInCoef_4 := CoefRamDout_3;
250	
251	    -- *** Stage 5 ***
252	    -- Multiplier input registers
253	    v.MultInTap_5 := r.MultInTap_4;
254	    v.MultInCoef_5 := r.MultInCoef_4;
255	    
256	    -- *** Stage 6 *** 
257	    -- Multiplication
258	    v.MultOut_6 := psi_fix_mult(r.MultInTap_5, in_fmt_g,
259	                                r.MultInCoef_5, coef_fmt_g,
260	                                MultFmt_c); -- Full precision, no rounding or saturation required
261	
262	    -- *** Stage 7 ***
263	    -- Accumulator
264	    if r.First(6) = '1' then
265	      AccuIn_v := (others => '0');
266	    else
267	      AccuIn_v := r.Accu_7;
268	    end if;
269	    v.Accu_7 := psi_fix_add(r.MultOut_6, MultFmt_c,
270	                          AccuIn_v, AccuFmt_c,
271	                          AccuFmt_c);   -- Overflows compensate at the end of the calculation and rounding not required
272	
273	    -- *** Stage 8 ***
274	    -- Rounding
275	    v.RndVld_8 := '0';
276	    if r.Last(7) = '1' then
277	      v.Rnd_8    := psi_fix_resize(r.Accu_7, AccuFmt_c, RndFmt_c, rnd_g, psi_fix_wrap);
278	      v.RndVld_8 := r.CalcOn(7);
279	    end if;
280	
281	    -- *** Stage 9 ***
282	    -- Output Handling and saturation
283	    v.OutVld_9 := r.RndVld_8;
284	    v.Output_9 := psi_fix_resize(r.Rnd_8, RndFmt_c, out_fmt_g, psi_fix_trunc, sat_g);
285	
286	    -- *** Status Output ***
287	    if (unsigned(r.Vld) /= 0) or (unsigned(r.CalcOn) /= 0) or (r.RndVld_8 = '1') then
288	      v.CalcOngoing := '1';
289	    else
290	      v.CalcOngoing := '0';
291	    end if;
292	
293	    -- *** Outputs ***
294	    vld_o  <= r.OutVld_9;
295	    dat_o  <= r.Output_9;
296	    busy_o <= r.CalcOngoing or r.Vld(0);
297	
298	    -- *** Assign to signal ***
299	    r_next <= v;
300	  end process;
301	
302	  --------------------------------------------
303	  -- Sequential Process
304	  --------------------------------------------
305	  p_seq : process(clk_i)
306	  begin
307	    if rising_edge(clk_i) then
308	      r <= r_next;
309	      if rst_i = rst_pol_g then
310	        r.Vld            <= (others => '0');
311	        r.ChannelNr(0)   <= (others => '0');
312	        r.CalcChnl_1     <= (others => '0');
313	        r.TapWrAddr_1    <= (others => '0');
314	        r.DecCnt_1       <= (others => '0');
315	        r.CalcOn         <= (others => '0');
316	        r.RndVld_8       <= '0';
317	        r.OutVld_9       <= '0';
318	        r.Last           <= (others => '0');
319	        r.ReplaceZero_4  <= '1';
320	        r.CalcOngoing    <= '0';
321	        r.FirstAfterRst  <= '1';
322	        r.FirstTapLoop_3 <= '1';
323	        r.TapCnt_1       <= cfg_taps_i;
324	      end if;
325	    end if;
326	  end process;
327	
328	  --------------------------------------------
329	  -- Component Instantiations
330	  --------------------------------------------
331	  -- Coefficient RAM for configurable coefficients
332	  g_nFixCoef : if not use_fix_coefs_g generate
333	    i_coef_ram : entity work.psi_fix_param_ram
334	      generic map(
335	        depth_g    => CoefMemDepthApplied_c,
336	        fmt_g      => coef_fmt_g,
337	        behavior_g => ram_behavior_g,
338	        init_g     => coefs_g
339	      )
340	      port map(
341	        ClkA  => coef_if_clk_i,
342	        AddrA => coef_if_addr_i,
343	        WrA   => coef_if_wr_i,
344	        DinA  => coef_if_wr_dat_i,
345	        DoutA => coef_if_rd_dat_o,
346	        ClkB  => clk_i,
347	        AddrB => r.CoefRdAddr_2,
348	        WrB   => '0',
349	        DinB  => (others => '0'),
350	        DoutB => CoefRamDout_3
351	      );
352	  end generate;
353	
354	  -- Coefficient ROM for non-configurable coefficients
355	  g_FixCoef : if use_fix_coefs_g generate
356	    -- Table must be generated outside of the ROM process to make code synthesizable
357	    g_CoefTable : for i in coefs_g'low to coefs_g'high generate
358	      CoefRom(i) <= psi_fix_from_real(coefs_g(i), coef_fmt_g);
359	    end generate;
360	
361	    -- Assign unused outputs
362	    coef_if_rd_dat_o <= (others => '0');
363	    -- Coefficient ROM
364	    p_coef_rom : process(clk_i)
365	    begin
366	      if rising_edge(clk_i) then
367	        CoefRamDout_3 <= CoefRom(to_integer(unsigned(r.CoefRdAddr_2)));
368	      end if;
369	    end process;
370	
371	  end generate;
372	
373	  DataRamWrAddr_1 <= r.ChannelNr(1) & r.TapWrAddr_1;
374	  DataRamRdAddr_2 <= r.CalcChnl_2 & r.TapRdAddr_2;
375	
376	  i_data_ram : entity work.psi_common_tdp_ram
377	    generic map(
378	      depth_g    => DataMemDepthApplied_c * channels_g,
379	      width_g    => psi_fix_size(in_fmt_g),
380	      behavior_g => ram_behavior_g
381	    )
382	    port map(
383	      a_clk_i  => clk_i,
384	      a_addr_i => DataRamWrAddr_1,
385	      a_wr_i   => r.Vld(1),
386	      a_dat_i  => r.InSig(1),
387	      a_dat_o => open,
388	      b_clk_i  => clk_i,
389	      b_addr_i => DataRamRdAddr_2,
390	      b_wr_i   => '0',
391	      b_dat_i  => (others => '0'),
392	      b_dat_o => DataRamDout_3
393	    );
394	
395	end architecture;
396	
397

