6	
7	------------------------------------------------------------------------------
8	-- Description
9	------------------------------------------------------------------------------
10	-- This component calculateas an FIR filter with the following limitations:
11	-- - Filter is calculated semi-parallel
12	-- - The number of channels is configurable
13	-- - All channels are processed time-division-multiplexed
14	-- - Coefficients are configurable but the same for each channel
15	-- - After the reset, the delay lines are not flushed. So tranisents may occur
16	-- - for the first few samples after resetting the filter.
17	------------------------------------------------------------------------------
18	library ieee;
19	use ieee.std_logic_1164.all;
20	use ieee.numeric_std.all;
21	use ieee.math_real.all;
22	
23	use work.psi_fix_pkg.all;
24	use work.psi_common_math_pkg.all;
25	use work.psi_common_array_pkg.all;
26	
27	-- $$ processes=stim, resp $$
28	entity psi_fix_fir_dec_semi_nch_chtdm_conf is
29	  generic(
30	    in_fmt_g                : psi_fix_fmt_t := (1, 0, 17);                                         -- input format FP $$ constant=(1,0,15) $$
31	    out_fmt_g               : psi_fix_fmt_t := (1, 0, 17);                                         -- output format FP $$ constant=(1,2,13) $$
32	    coef_fmt_g              : psi_fix_fmt_t := (1, 0, 17);                                         -- coef format FP $$ constant=(1,0,17) $$
33	    channels_g              : natural     := 4;                                                    -- number of parallel channels $$ export=true $$
34	    multipliers_g           : natural     := 4;                                                    -- number of multipliers to use in parallel
35	    ratio_g                 : natural     := 8;                                                    -- decimation ratio
36	    taps_g                  : natural     := 32;                                                   -- number of taps implemented
37	    rnd_g                   : psi_fix_rnd_t := psi_fix_round;                                      -- round or trunc
38	    sat_g                   : psi_fix_sat_t := psi_fix_sat;                                        -- sat or wrap
39	    use_fix_coefs_g         : boolean     := false;                                                -- if true fixed coefficient instead of configurable
40	    full_inp_rate_support_g : boolean     := false;                                                -- True = valid signa can be High all the time
41	    ram_behavior_g          : string      := "RBW";                                                -- "RBW" = read-before-write, "WBR" = write-before-read
42	    coefs_g                 : t_areal     := (0.1, 0.2);                                           -- inital value for coefficients
43	    impl_flush_if_g         : boolean     := false                                                 -- implement memory flushing interface
44	  );
45	  port(
46	    clk_i         : in  std_logic;                                                                 -- clk system $$ type=clk; freq=100e6 $$
47	    rst_i         : in  std_logic;                                                                 -- rst system $$ type=rst; clk=Clk $$
48	    dat_i         : in  std_logic_vector(psi_fix_size(in_fmt_g) - 1 downto 0);                     -- data input
49	    vld_i         : in  std_logic;                                                                 -- valid input - AXI-S handshaking
50	    dat_o         : out std_logic_vector(psi_fix_size(out_fmt_g) - 1 downto 0);                    -- Output data, one channel is passed after the other
51	    vld_o         : out std_logic;                                                                 -- valid output signal - AXI-S handshaking
52	    -- Coefficient interface
53	    coef_wr_i     : in  std_logic                                            := '0';               -- Coefficient write enable signal
54	    coef_addr_i   : in  std_logic_vector(log2ceil(taps_g) - 1 downto 0)      := (others => '0');   -- Address of the coefficient to access
55	    coef_wr_dat_i : in  std_logic_vector(psi_fix_size(coef_fmt_g) - 1 downto 0) := (others => '0');-- Coefficient value for write access (CoefWr = 1)
56	    -- Delay-line flushing interface
57	    flush_mem_i   : in  std_logic                                            := '0';               -- Inject a pulse to flush all data memories (usually done after reset).
58	    flush_done_o  : out std_logic;                                                                 -- A pulse on this port indicates that a flush started by flush_mem = '1' was completed.
59	    -- Status Output
60	    busy_o        : out std_logic                                                                  -- busy signal output status
61	  );
62	end entity;
63	
64	------------------------------------------------------------------------------
65	-- Architecture Declaration
66	------------------------------------------------------------------------------
67	architecture rtl of psi_fix_fir_dec_semi_nch_chtdm_conf is
68	
69	  -- RAM Calculation
70	  constant TapsPerStage_c     : natural := integer(ceil(real(taps_g) / real(multipliers_g)));
71	  constant RamPerChPerStage_c : natural := 2**log2ceil(TapsPerStage_c + ratio_g + 1);
72	  constant TapSelBits_c       : natural := log2ceil(RamPerChPerStage_c);
73	  constant RamPerStage_c      : natural := 2**log2ceil(RamPerChPerStage_c * channels_g);
74	  constant RamAddrBits_c      : natural := log2ceil(RamPerStage_c);
75	  constant ChSelBits_c        : natural := log2ceil(channels_g);
76	
77	  -- Constants
78	  constant AccuFmt_c       : psi_fix_fmt_t := (1, in_fmt_g.I + coef_fmt_g.I + log2ceil(multipliers_g), in_fmt_g.F + coef_fmt_g.F);
79	  constant RoundFmt_c      : psi_fix_fmt_t := (1, AccuFmt_c.I + 1, out_fmt_g.F);
80	  constant CyclesPerCalc_c : integer     := integer(ceil(real(taps_g) / real(multipliers_g)));
81	
82	  -- types
83	  type TapAddr_a is array (natural range <>) of unsigned(TapSelBits_c - 1 downto 0);
84	  type Channel_a is array (natural range <>) of unsigned(ChSelBits_c - 1 downto 0);
85	  type Data_a is array (natural range <>) of std_logic_vector(dat_i'range);
86	  type Addr_a is array (natural range <>) of std_logic_vector(RamAddrBits_c - 1 downto 0);
87	  type Coef_a is array (natural range <>) of std_logic_vector(psi_fix_size(coef_fmt_g) - 1 downto 0);
88	  type Accu_a is array (natural range <>) of std_logic_vector(psi_fix_size(AccuFmt_c) - 1 downto 0);
89	  type CoefAddr_a is array (natural range <>) of std_logic_vector(log2ceil(TapsPerStage_c) - 1 downto 0);
90	
91	  -- Two process method
92	  type two_process_r is record
93	    Vld             : std_logic_vector(0 to max(1, multipliers_g));
94	    Data_0          : std_logic_vector(dat_i'range);
95	    Data_1          : std_logic_vector(dat_i'range);
96	    DecCnt_0        : integer range 0 to ratio_g - 1;
97	    ChCnt           : Channel_a(0 to max(multipliers_g, 1));
98	    TapUpdWrAddr_0  : unsigned(TapSelBits_c - 1 downto 0);
99	    TapUpdAddr      : TapAddr_a(1 to max(multipliers_g, 1));
100	    CalcStartLoop_1 : std_logic;
101	    CalcFirst       : std_logic_vector(2 to 7 + multipliers_g);
102	    CalcLast        : std_logic_vector(2 to 7 + multipliers_g);
103	    CalcCycLeft_2   : integer range 0 to CyclesPerCalc_c - 1;
104	    CalcChannel_2   : unsigned(log2ceil(channels_g) - 1 downto 0);
105	    CalcFirstTap_2  : unsigned(TapSelBits_c - 1 downto 0);
106	    CalcRunning     : std_logic_vector(2 to 7 + multipliers_g);
107	    TapRdAddr_2     : unsigned(TapSelBits_c - 1 downto 0);
108	    CoefRdIdx_2     : unsigned(TapSelBits_c - 1 downto 0);
109	    CoefRdAddr      : TapAddr_a(3 to 3 + multipliers_g);
110	    TapRdAddr       : Addr_a(3 to 3 + multipliers_g);
111	    Accu_8n         : std_logic_vector(psi_fix_size(AccuFmt_c) - 1 downto 0);
112	    OutVld_n        : std_logic_vector(8 to 10);
113	    Rnd_9n          : std_logic_vector(psi_fix_size(RoundFmt_c) - 1 downto 0);
114	    OutData_10n     : std_logic_vector(psi_fix_size(out_fmt_g) - 1 downto 0);
115	    -- Coefficient write access (not in calculation pipeline)
116	    CoefWrStg       : std_logic_vector(0 to multipliers_g - 1);
117	    CoefWrDataStg   : std_logic_vector(coef_wr_dat_i'range);
118	    CoefAddrStg     : CoefAddr_a(0 to multipliers_g - 1);
119	    -- Memory Flusing
120	    FlushActive     : std_logic;
121	    FlushAddr       : std_logic_vector(RamAddrBits_c - 1 downto 0);
122	    FlushDone       : std_logic;
123	    -- Status
124	    CalcOngoing     : std_logic;
125	  end record;
126	  signal r, r_next : two_process_r;
127	
128	  -- Functions
129	  function GetCoefs(stage : integer) return Coef_a is
130	    variable Coefs_v : Coef_a(0 to TapsPerStage_c - 1) := (others => (others => '0'));
131	    variable Idx_v   : natural                         := stage * multipliers_g;
132	  begin
133	    if use_fix_coefs_g then
134	      for i in 0 to TapsPerStage_c - 1 loop
135	        if (stage * TapsPerStage_c + i < taps_g) and (stage * TapsPerStage_c + i < coefs_g'length) then
136	          Coefs_v(i) := psi_fix_from_real(coefs_g(stage * TapsPerStage_c + i), coef_fmt_g);
137	        end if;
138	      end loop;
139	    end if;
140	    return Coefs_v;
141	  end function;
142	
143	  function GetCoefsReal(stage : integer) return t_areal is
144	    variable Coefs_v : t_areal(0 to TapsPerStage_c - 1) := (others => 0.0);
145	    variable Idx_v   : natural                          := stage * multipliers_g;
146	  begin
147	    for i in 0 to TapsPerStage_c - 1 loop
148	      if (stage * TapsPerStage_c + i < taps_g) and (stage * TapsPerStage_c + i < coefs_g'length) then
149	        Coefs_v(i) := coefs_g(stage * TapsPerStage_c + i);
150	      end if;
151	    end loop;
152	    return Coefs_v;
153	  end function;
154	
155	  -- Component Instantiation Signals
156	  signal DataInChain : Data_a(1 to multipliers_g + 1);
157	  signal AccuChain   : Accu_a(7 to 7 + multipliers_g);
158	  signal AccuVld     : std_logic_vector(8 to 8 + multipliers_g - 1);
159	
160	begin
161	
162	  --------------------------------------------
163	  -- Asserts
164	  --------------------------------------------
165	  p_assert : process(clk_i)
166	  begin
167	    if rising_edge(clk_i) then
168	      -- Check if input rate is correct
169	      if not full_inp_rate_support_g then
170	        assert (r.Vld(0) /= '1') or (r.Vld(1) /= '1')
171	        report "###ERROR###: psi_fix_fir_dec_semi_nch_chtdm_conf implemented with full_inp_rate_support_g=false but InVld asserted for two consecutive clock cycles!"
172	        severity error;
173	      end if;
174	      -- Check if processing power is sufficient and print errors otherwise so the problem is detected easily during simulations
175	      if r.CalcStartLoop_1 = '1' then
176	        assert (r.CalcRunning(2) = '0') or (((r.CalcChannel_2 = channels_g - 1) or (channels_g = 1)) and (r.CalcLast(2) = '1'))
177	        report "###ERROR###: psi_fix_fir_dec_semi_nch_chtdm_conf insufficient processing power to handle data rate! (multipliers_g is set too low!)"
178	        severity error;
179	      end if;
180	    end if;
181	  end process;
182	
183	  --------------------------------------------
184	  -- Combinatorial Process
185	  --------------------------------------------
186	  p_comb : process(r, vld_i, dat_i, AccuChain, AccuVld, coef_wr_dat_i, coef_addr_i, coef_wr_i, flush_mem_i)
187	    variable v           : two_process_r;
188	    variable StartLoop_v : boolean;
189	
190	  begin
191	    -- *** Hold variables stable ***
192	    v := r;
193	
194	    -- *** Pipe Handling ***
195	    v.Vld(v.Vld'low + 1 to v.Vld'high)                         := r.Vld(r.Vld'low to r.Vld'high - 1);
196	    v.TapUpdAddr(v.TapUpdAddr'low + 1 to v.TapUpdAddr'high)    := r.TapUpdAddr(r.TapUpdAddr'low to r.TapUpdAddr'high - 1);
197	    v.CoefRdAddr(v.CoefRdAddr'low + 1 to v.CoefRdAddr'high)    := r.CoefRdAddr(r.CoefRdAddr'low to r.CoefRdAddr'high - 1);
198	    v.TapRdAddr(v.TapRdAddr'low + 1 to v.TapRdAddr'high)       := r.TapRdAddr(r.TapRdAddr'low to r.TapRdAddr'high - 1);
199	    v.CalcRunning(v.CalcRunning'low + 1 to v.CalcRunning'high) := r.CalcRunning(r.CalcRunning'low to r.CalcRunning'high - 1);
200	    v.CalcFirst(v.CalcFirst'low + 1 to v.CalcFirst'high)       := r.CalcFirst(r.CalcFirst'low to r.CalcFirst'high - 1);
201	    v.CalcLast(v.CalcLast'low + 1 to v.CalcLast'high)          := r.CalcLast(r.CalcLast'low to r.CalcLast'high - 1);
202	    v.OutVld_n(v.OutVld_n'low + 1 to v.OutVld_n'high)          := r.OutVld_n(r.OutVld_n'low to r.OutVld_n'high - 1);
203	    v.ChCnt(v.ChCnt'low + 1 to v.ChCnt'high)                   := r.ChCnt(r.ChCnt'low to r.ChCnt'high - 1);
204	
205	    -- *** Stage 0 ***
206	    v.Vld(0) := vld_i;
207	    v.Data_0 := dat_i;
208	    if r.Vld(0) = '1' then
209	      if (r.ChCnt(0) = channels_g - 1) or (channels_g = 1) then
210	        v.ChCnt(0)       := (others => '0');
211	        if r.DecCnt_0 = 0 then
212	          v.DecCnt_0 := ratio_g - 1;
213	        else
214	          v.DecCnt_0 := r.DecCnt_0 - 1;
215	        end if;
216	        v.TapUpdWrAddr_0 := r.TapUpdWrAddr_0 + 1;
217	      else
218	        v.ChCnt(0) := r.ChCnt(0) + 1;
219	      end if;
220	    end if;
221	
222	    -- *** Stage 1 ***
223	    v.Data_1          := r.Data_0;
224	    v.CalcStartLoop_1 := '0';
225	    if r.Vld(0) = '1' and r.DecCnt_0 = 0 and ((r.ChCnt(0) = channels_g - 1) or (channels_g = 1)) then
226	      v.CalcStartLoop_1 := '1';
227	    end if;
228	    -- Write on the cycle a new sample is arriving
229	    if r.Vld(0) = '1' then
230	      v.TapUpdAddr(1) := r.TapUpdWrAddr_0;
231	    -- Read in between to execute Read-before-write literally
232	    elsif not full_inp_rate_support_g then
233	      v.TapUpdAddr(1) := r.TapUpdWrAddr_0 - TapsPerStage_c;
234	    end if;
235	
236	    -- *** Stage 2 ***
237	    -- Default values
238	    v.CalcFirst(2) := '0';
239	    v.CalcLast(2)  := '0';
240	    StartLoop_v    := false;
241	    -- Start calculation loop
242	    if r.CalcStartLoop_1 = '1' then
243	      v.CalcChannel_2  := (others => '0');
244	      v.CalcFirstTap_2 := r.TapUpdAddr(1);
245	      v.TapRdAddr_2    := r.TapUpdAddr(1);
246	      StartLoop_v      := true;
247	      v.CalcRunning(2) := '1';
248	    elsif r.CalcRunning(2) = '1' then
249	      v.CoefRdIdx_2 := r.CoefRdIdx_2 - 1;
250	      v.TapRdAddr_2 := r.TapRdAddr_2 + 1;
251	      if r.CalcCycLeft_2 <= 1 then
252	        v.CalcLast(2) := '1';
253	      end if;
254	      if r.CalcCycLeft_2 /= 0 then
255	        v.CalcCycLeft_2 := r.CalcCycLeft_2 - 1;
256	      end if;
257	    end if;
258	    -- After calculation is done ...
259	    if (r.CalcLast(2) = '1') and (r.CalcRunning(2) = '1') then
260	      v.CalcLast(2) := '0';
261	      -- ... start next channel if the current channe lwas not the last one
262	      if (r.CalcChannel_2 /= channels_g - 1) and (channels_g /= 1) then
263	        v.CalcChannel_2 := r.CalcChannel_2 + 1;
264	        v.TapRdAddr_2   := r.CalcFirstTap_2;
265	        StartLoop_v     := true;
266	      -- ... finish calculation loop otherwise
267	      elsif r.CalcStartLoop_1 = '0' then
268	        v.CalcRunning(2) := '0';
269	      end if;
270	    end if;
271	    -- Handle start loop behavior (shared code in two places)
272	    if StartLoop_v then
273	      v.CalcFirst(2)  := '1';
274	      v.CalcCycLeft_2 := CyclesPerCalc_c - 1;
275	      v.CoefRdIdx_2   := to_unsigned(TapsPerStage_c - 1, v.CoefRdIdx_2'length);
276	      if taps_g <= multipliers_g then
277	        v.CalcLast(2) := '1';
278	      end if;
279	    end if;
280	
281	    -- *** Stage 3 ***
282	    v.CoefRdAddr(3) := r.CoefRdIdx_2;
283	    v.TapRdAddr(3)  := std_logic_vector(r.CalcChannel_2) & std_logic_vector(signed(r.TapRdAddr_2) - TapsPerStage_c + 1);
284	
285	    -- *** Memory Flushing (happens outside of pipeline)
286	    v.FlushDone := '0';
287	    if impl_flush_if_g then
288	      -- start flushing
289	      if flush_mem_i = '1' then
290	        v.FlushActive := '1';
291	        v.FlushAddr   := (others => '0');
292	      -- End flushing
293	      elsif signed(r.FlushAddr) = -1 then
294	        v.FlushActive := '0';
295	        v.FlushDone   := '1';
296	        v.FlushAddr   := (others => '0');
297	      -- Continue Flushing
298	      elsif r.FlushActive = '1' then
299	        v.FlushAddr := std_logic_vector(unsigned(r.FlushAddr) + 1);
300	      end if;
301	    end if;
302	
303	    -- *** Output Summation ***
304	    v.OutVld_n(8) := '0';
305	    if r.CalcRunning(7 + multipliers_g) = '1' and AccuVld(7 + multipliers_g) = '1' then
306	      if r.CalcFirst(7 + multipliers_g) = '1' then
307	        v.Accu_8n := AccuChain(7 + multipliers_g);
308	      else
309	        v.Accu_8n := psi_fix_add(r.Accu_8n, AccuFmt_c, AccuChain(7 + multipliers_g), AccuFmt_c, AccuFmt_c);
310	      end if;
311	      if r.CalcLast(7 + multipliers_g) = '1' then
312	        v.OutVld_n(8) := '1';
313	      end if;
314	    end if;
315	
316	    -- *** Output Rounding ***
317	    v.Rnd_9n := psi_fix_resize(r.Accu_8n, AccuFmt_c, RoundFmt_c, rnd_g, psi_fix_wrap);
318	
319	    -- *** Output Saturation ***
320	    v.OutData_10n := psi_fix_resize(r.Rnd_9n, RoundFmt_c, out_fmt_g, psi_fix_trunc, sat_g);
321	
322	    -- *** Coefficient Write Access (not in calculation pipeline) ***
323	    if not use_fix_coefs_g then
324	      v.CoefWrDataStg := coef_wr_dat_i;
325	      v.CoefWrStg     := (others => '0');
326	
327	      for m in 0 to multipliers_g - 1 loop
328	        if unsigned(coef_addr_i) >= m * TapsPerStage_c and unsigned(coef_addr_i) < (m + 1) * TapsPerStage_c then
329	          v.CoefWrStg(m) := coef_wr_i;
330	        end if;
331	        v.CoefAddrStg(m) := std_logic_vector(resize(unsigned(coef_addr_i) - m * TapsPerStage_c, v.CoefAddrStg(m)'length));
332	      end loop;
333	    end if;
334	
335	    -- *** Status Output ***
336	    if (unsigned(r.Vld) /= 0) or (unsigned(r.CalcRunning) /= 0) or (unsigned(r.OutVld_n(r.OutVld_n'low to r.OutVld_n'high - 1)) /= 0) then
337	      v.CalcOngoing := '1';
338	    else
339	      v.CalcOngoing := '0';
340	    end if;
341	
342	    -- *** Outputs ***
343	    dat_o        <= r.OutData_10n;
344	    vld_o        <= r.OutVld_n(10);
345	    flush_done_o <= r.FlushDone;
346	    busy_o       <= r.CalcOngoing or r.Vld(0);
347	
348	    -- *** Assign to signal ***
349	    r_next <= v;
350	  end process;
351	
352	  --------------------------------------------
353	  -- Sequential Process
354	  --------------------------------------------
355	  p_seq : process(clk_i)
356	  begin
357	    if rising_edge(clk_i) then
358	      r <= r_next;
359	      if rst_i = '1' then
360	        r.Vld            <= (others => '0');
361	        r.DecCnt_0       <= 0;
362	        r.ChCnt(0)       <= (others => '0');
363	        r.TapUpdWrAddr_0 <= (others => '0');
364	        r.CalcRunning    <= (others => '0');
365	        r.FlushActive    <= '0';
366	        r.FlushDone      <= '0';
367	        r.CalcOngoing    <= '0';
368	      end if;
369	    end if;
370	  end process;
371	
372	  --------------------------------------------
373	  -- Component Instantiations
374	  --------------------------------------------
375	  DataInChain(1) <= r.Data_1;
376	  AccuChain(7)   <= (others => '0');
377	  g_mac : for i in 0 to multipliers_g - 1 generate
378	    signal DataWrAddr_1i   : std_logic_vector(RamAddrBits_c - 1 downto 0);
379	    signal DataWr          : std_logic;
380	    signal DataDin         : std_logic_vector(dat_i'range);
381	    signal RdData_4i       : std_logic_vector(dat_i'range);
382	    signal Coef_4i         : std_logic_vector(psi_fix_size(coef_fmt_g) - 1 downto 0);
383	    constant StageCoefs_c  : Coef_a(0 to TapsPerStage_c - 1)  := GetCoefs(i);
384	    constant StageCoefsR_c : t_areal(0 to TapsPerStage_c - 1) := GetCoefsReal(i);
385	    signal RamRdData       : std_logic_vector(dat_i'range);
386	    signal FullRateDel     : std_logic_vector(dat_i'range);
387	  begin
388	
389	    -- *** Tap Data RAM***
390	    g_noflush : if not impl_flush_if_g generate
391	      DataWrAddr_1i <= std_logic_vector(r.ChCnt(i + 1)) & std_logic_vector(r.TapUpdAddr(i + 1));
392	      DataWr        <= r.Vld(i + 1);
393	      DataDin       <= DataInChain(i + 1);
394	    end generate;
395	    g_flush : if impl_flush_if_g generate
396	      DataWrAddr_1i <= std_logic_vector(r.ChCnt(i + 1)) & std_logic_vector(r.TapUpdAddr(i + 1)) when r.FlushActive = '0' else r.FlushAddr;
397	      DataWr        <= r.Vld(i + 1) when r.FlushActive = '0' else '1';
398	      DataDin       <= DataInChain(i + 1) when r.FlushActive = '0' else (others => '0');
399	    end generate;
400	
401	    i_data_ram : entity work.psi_common_tdp_ram
402	      generic map(
403	        depth_g    => RamPerStage_c,
404	        width_g    => psi_fix_size(in_fmt_g),
405	        behavior_g => ram_behavior_g
406	      )
407	      port map(
408	        a_clk_i  => clk_i,
409	        a_addr_i => DataWrAddr_1i,
410	        a_wr_i   => DataWr,
411	        a_dat_i  => DataDin,
412	        a_dat_o => RamRdData,
413	        b_clk_i  => clk_i,
414	        b_addr_i => r.TapRdAddr(3 + i),
415	        b_wr_i   => '0',
416	        b_dat_i  => (others => '0'),
417	        b_dat_o => RdData_4i
418	      );
419	
420	    -- *** Tap data delay  ***
421	    -- for full input rate support, a separate delay chain is used
422	    g_fullrate : if full_inp_rate_support_g generate
423	      i_tapdelay : entity work.psi_common_delay
424	        generic map(
425	          width_g       => psi_fix_size(in_fmt_g),
426	          delay_g       => channels_g * TapsPerStage_c,
427	          resource_g    => "AUTO",
428	          rst_state_g    => impl_flush_if_g, -- the tap delay only needs to be reset cleanly if the memory can be flushed too. Otherwise leftovers are in memory anyways.
429	          ram_behavior_g => ram_behavior_g
430	        )
431	        port map(
432	          clk_i     => clk_i,
433	          rst_i     => rst_i,
434	          dat_i  => DataInChain(i + 1),
435	          vld_i   => r.Vld(i + 1),
436	          dat_o => FullRateDel
437	        );
438	    end generate;
439	    -- Otherwise the RAM output is delayed
440	    p_ram_fw_del : process(clk_i)
441	    begin
442	      if rising_edge(clk_i) then
443	        if not full_inp_rate_support_g then
444	          DataInChain(i + 2) <= RamRdData;
445	        else
446	          DataInChain(i + 2) <= FullRateDel;
447	        end if;
448	      end if;
449	    end process;
450	
451	    -- *** Coefficient ROM (fixed coefs) ***
452	    g_coefrom : if use_fix_coefs_g generate
453	      p_coef_rom : process(clk_i)
454	      begin
455	        if rising_edge(clk_i) then
456	          if r.CoefRdAddr(3 + i) < TapsPerStage_c then
457	            Coef_4i <= StageCoefs_c(to_integer(r.CoefRdAddr(3 + i)));
458	          else
459	            Coef_4i <= (others => '0');
460	          end if;
461	        end if;
462	      end process;
463	    end generate;
464	
465	    -- *** Coefficient RAM (configurable coefs) ***
466	    g_coefram : if not use_fix_coefs_g generate
467	      signal RdAddr : std_logic_vector(log2ceil(TapsPerStage_c) - 1 downto 0);
468	    begin
469	      RdAddr <= std_logic_vector(r.CoefRdAddr(3 + i)(RdAddr'range));
470	      i_coef_ram : entity work.psi_fix_param_ram
471	        generic map(
472	          depth_g    => 2**log2ceil(TapsPerStage_c),
473	          fmt_g      => coef_fmt_g,
474	          behavior_g => ram_behavior_g,
475	          init_g     => StageCoefsR_c
476	        )
477	        port map(
478	          ClkA  => clk_i,
479	          AddrA => r.CoefAddrStg(i),
480	          WrA   => r.CoefWrStg(i),
481	          DinA  => r.CoefWrDataStg,
482	          DoutA => open,
483	          ClkB  => clk_i,
484	          AddrB => RdAddr,
485	          WrB   => '0',
486	          DinB  => (others => '0'),
487	          DoutB => Coef_4i
488	        );
489	    end generate;
490	
491	    -- *** Multiply and Add ***
492	    i_multadd : entity work.psi_fix_mult_add_stage
493	      generic map(
494	        in_a_fmt_g    => in_fmt_g,
495	        in_b_fmt_g    => coef_fmt_g,
496	        add_fmt_g    => AccuFmt_c,
497	        in_b_is_coef_g => false
498	      )
499	      port map(
500	        clk_i            => clk_i,
501	        rst_i            => rst_i,
502	        vld_a_i         => r.CalcRunning(4 + i),
503	        dat_a_i            => RdData_4i,
504	        del2_a_o        => open,
505	        vld_b_i         => r.CalcRunning(4 + i),
506	        dat_b_i            => Coef_4i,
507	        del2_b_o        => open,
508	        chain_add_i     => AccuChain(7 + i),
509	        chain_add_o    => AccuChain(8 + i),
510	        chain_add_vld_o => AccuVld(8 + i)
511	      );
512	
513	  end generate;
514	
515	end architecture;
516	
517

