4	--  Authors: Oliver Bruendler
5	------------------------------------------------------------------------------
6	
7	------------------------------------------------------------------------------
8	-- Description
9	------------------------------------------------------------------------------
10	-- Multiply-Add stage that also fits well into chained DSP slices as common
11	-- to many FPGA families.
12	-- It fits best to DSP slice columns(as for example present in Xilinx 7-Series,
13	-- Xilinx 6-series, Xilinx Spartan3ADSP, etc.) but can also be implemented using
14	-- registers and multipliers. As a result it is synthesizable for all FPGAs but
15	-- not optimal if there are no DSP columns.
16	
17	------------------------------------------------------------------------------
18	-- Libraries
19	------------------------------------------------------------------------------
20	library ieee;
21	use ieee.std_logic_1164.all;
22	use ieee.numeric_std.all;
23	
24	use work.psi_fix_pkg.all;
25	use work.psi_common_math_pkg.all;
26	use work.psi_common_array_pkg.all;
27	
28	entity psi_fix_mult_add_stage is
29	  generic(
30	    in_a_fmt_g     : psi_fix_fmt_t := (1, 0, 17);                                   -- data A input format FP
31	    in_b_fmt_g     : psi_fix_fmt_t := (1, 0, 17);                                   -- data B input format FP
32	    add_fmt_g      : psi_fix_fmt_t := (1, 0, 17);                                   -- output format FP
33	    in_b_is_coef_g : boolean       := false;                                        -- If True, InBVld is only used to write a cst coef to the input reg of the DSP slice
34	                                                                                    -- If False, InBVld leads to a multiply-add operation and is propagated to AddChainOutVld
35	    rst_pol_g      : std_logic     := '1'                                           -- reset polarity
36	  );
37	  port(
38	    clk_i           : in  std_logic;                                                -- system clock $$ type=clk; freq=100e6 $$
39	    rst_i           : in  std_logic;                                                -- system reset $$ type=rst; clk=clk_i $$
40	    dat_a_i         : in  std_logic_vector(psi_fix_size(in_a_fmt_g) - 1 downto 0);  -- data in put a
41	    vld_a_i         : in  std_logic;                                                -- vld a
42	    del2_a_o        : out std_logic_vector(psi_fix_size(in_a_fmt_g) - 1 downto 0);  -- registred data a by 2 clock cycles (efficient pipeline for FIR implementation)
43	    dat_b_i         : in  std_logic_vector(psi_fix_size(in_b_fmt_g) - 1 downto 0);  -- data input b
44	    vld_b_i         : in  std_logic;                                                -- vld b
45	    del2_b_o        : out std_logic_vector(psi_fix_size(in_b_fmt_g) - 1 downto 0);  -- registered data b by 2 clock cycles (efficient pipeline for FIR implementation)
46	    chain_add_i     : in  std_logic_vector(psi_fix_size(add_fmt_g) - 1 downto 0);   -- adder chain input data
47	    chain_add_o     : out std_logic_vector(psi_fix_size(add_fmt_g) - 1 downto 0);   -- adder chain output data
48	    chain_add_vld_o : out std_logic                                                 -- adder chain output valid
49	  );
50	end entity;
51	
52	architecture rtl of psi_fix_mult_add_stage is
53	
54	  constant MultFmt_c : psi_fix_fmt_t := (max(in_a_fmt_g.S, in_b_fmt_g.S), in_a_fmt_g.I + in_b_fmt_g.I + 1, in_a_fmt_g.F + in_b_fmt_g.F);
55	  signal InAReg0     : std_logic_vector(dat_a_i'range);
56	  signal InAReg1     : std_logic_vector(dat_a_i'range);
57	  signal InBReg0     : std_logic_vector(dat_b_i'range);
58	  signal InBReg1     : std_logic_vector(dat_b_i'range);
59	  signal MultReg     : std_logic_vector(psi_fix_size(MultFmt_c) - 1 downto 0);
60	  signal AddReg      : std_logic_vector(psi_fix_size(add_fmt_g) - 1 downto 0);
61	  signal Vld0        : std_logic;
62	  signal Vld1        : std_logic;
63	  signal Vld2        : std_logic;
64	  signal Vld3        : std_logic;
65	
66	begin
67	  -- DSP Slice description
68	  p_dsp : process(clk_i)
69	  begin
70	    if rising_edge(clk_i) then
71	      -- *** Stage 0 ***
72	      if vld_a_i = '1' then
73	        InAReg0 <= dat_a_i;
74	      end if;
75	      if vld_b_i = '1' then
76	        InBReg0 <= dat_b_i;
77	      end if;
78	      -- If B is used as data port, calculations must be updated on new B values
79	      if not in_b_is_coef_g then
80	        Vld0 <= vld_a_i or vld_b_i;
81	      -- If B is used as asynchronously updated coefficient, a change to the coefficient does not lead to an output sample
82	      else
83	        Vld0 <= vld_a_i;
84	      end if;
85	      -- *** Stage 1 ***
86	      if Vld0 = '1' then
87	        InAReg1 <= InAReg0;
88	        InBReg1 <= InBReg0;
89	      end if;
90	      Vld1 <= Vld0;
91	      -- *** Stage 2 ***
92	      if Vld1 = '1' then
93	        MultReg <= psi_fix_mult(InAReg1, in_a_fmt_g, InBReg1, in_b_fmt_g, MultFmt_c);
94	      end if;
95	      Vld2 <= Vld1;
96	      -- *** Stage 3 ***
97	      if Vld2 = '1' then
98	        AddReg <= psi_fix_add(chain_add_i, add_fmt_g, MultReg, MultFmt_c, add_fmt_g);
99	      end if;
100	      if rst_i = rst_pol_g then
101	        Vld0    <= '0';
102	        Vld1    <= '0';
103	        Vld2    <= '0';
104	        InAReg0 <= (others => '0');
105	        InAReg1 <= (others => '0');
106	        InBReg0 <= (others => '0');
107	        InBReg1 <= (others => '0');
108	      end if;
109	      Vld3 <= Vld2;
110	    end if;
111	  end process;
112	
113	  -- Outputs
114	  chain_add_o     <= AddReg;
115	  del2_a_o        <= InAReg1;
116	  del2_b_o        <= InBReg1;
117	  chain_add_vld_o <= Vld3;
118	
119	end architecture;
120

